import React, { useEffect, useState, useRef } from 'react'
import './styles.css'


function useRafProgress({ duration, active, onComplete }) {
    const [progress, setProgress] = useState(0)
    const rafRef = useRef(null)
    const startref = useRef(null)
    console.log('progress', progress)
    function animate(ts) {
        if (!startref.current) {
            startref.current = ts
        }
        const elapsed = ts - startref.current
        const percent = Math.min((elapsed / duration) * 100, 100)
        setProgress(percent)
        if (elapsed < duration) {
            requestAnimationFrame(animate)
        } else {
            onComplete?.()
        }
    }
    useEffect(() => {
        if (!active) return
        rafRef.current = requestAnimationFrame(animate)
        return () => {
            cancelAnimationFrame(rafRef.current)
            startref.current = null
        }
    }, [duration, active, onComplete])
    return progress
}

function ProgressBar({ active, duration, onComplete }) {
    const progress = useRafProgress({
        duration,
        active,
        onComplete,
    });
    return (
        <div className="progress-bar-container">
            <div style={{ width: `${progress}%` }} className='progress-bar'></div>
        </div>
    )
}

export default React.memo(ProgressBar)
